final:
module RefModule(
    input clk,
    input shift,
    input [3:0] D,
    output reg Q3
);reg [3:0] unused_reg_data;

always @(posedge clk) begin
    if (shift == 1'b0) begin
        unused_reg_data <= D;
    end else begin
        unused_reg_data <= {unused_reg_data[2:0], D[3]};
    end
end

assign Q3 = unused_reg_data[3];

endmodule
